  ('manus_ai_2026_05_03', 'USA-based scholarships', 'Hubert Humphrey Fellowship Program', 'US government', 'United States', NULL, 'stipend', 'Supports 10 months of academic study in the US (details on specific coverage not provided on this page, but generally comprehensive).', NULL, ARRAY['non_degree']::text[], NULL, NULL, 'International, experienced professionals from eligible countries.', 'Experienced professionals from eligible countries, wishing to undertake 10 months of academic study in the US. Does not support degree qualifications.', NULL, 'varies', NULL, NULL, 'US government', 'Non-degree academic study (experienced professionals)', 'International, experienced professionals from eligible countries.', 'Supports 10 months of academic study in the US (details on specific coverage not provided on this page, but generally comprehensive).', 'Not specified.', 'Experienced professionals from eligible countries, wishing to undertake 10 months of academic study in the US. Does not support degree qualifications.', 'Not specified on this page (generally varies by country).', 'Not specified on this page (generally managed by US Embassies/Fulbright Commissions).', TRUE),
