  ('manus_ai_2026_05_03', 'Canadian scholarships and fellowships for developing country students', 'Pearson International Scholarship (University of Toronto)', 'University of Toronto, Canada', 'Canada', 'https://future.utoronto.ca/pearson-scholarships', 'stipend', 'Full funding for 4 years.', NULL, ARRAY['master','bachelor']::text[], NULL, NULL, 'International students (non-Canadian requiring a study permit).', 'Exceptional academic achievement and creativity, recognized as leaders within their school, currently in final year of secondary school or graduated no earlier than June of previous year. Must be nominated by their schools.', NULL, 'fixed', NULL, NULL, 'University of Toronto, Canada', 'Undergraduate', 'International students (non-Canadian requiring a study permit).', 'Full funding for 4 years.', 'Not explicitly stated.', 'Exceptional academic achievement and creativity, recognized as leaders within their school, currently in final year of secondary school or graduated no earlier than June of previous year. Must be nominated by their schools.', 'Not explicitly stated on this page, but typically in the fall for the following academic year.', 'https://future.utoronto.ca/pearson-scholarships', TRUE),
  ('manus_ai_2026_05_03', 'Canadian scholarships and fellowships for developing country students', 'Global Leader of Tomorrow Scholarship (York University)', 'York University, Canada', 'Canada', 'https://futurestudents.yorku.ca/financing-your-degree/international-scholarships', 'stipend', '$80,000 ($20,000 x 4 years).', 80000.0, ARRAY['master','bachelor']::text[], NULL, NULL, 'International students requiring a Study Permit to study in Canada.', 'Applying directly from high school (no more than two years after graduation, no previous university or college studies), excellent academic record ("A" average or equivalent), demonstrated leadership through community service or excellence in arts, sports, or other areas of individual achievement. Must apply to specific faculties.', NULL, 'fixed', NULL, NULL, 'York University, Canada', 'Undergraduate', 'International students requiring a Study Permit to study in Canada.', '$80,000 ($20,000 x 4 years).', 'Not explicitly stated.', 'Applying directly from high school (no more than two years after graduation, no previous university or college studies), excellent academic record ("A" average or equivalent), demonstrated leadership through community service or excellence in arts, sports, or other areas of individual achievement. Must apply to specific faculties.', 'Not explicitly stated on this page, but typically in the fall for the following academic year.', 'https://futurestudents.yorku.ca/financing-your-degree/international-scholarships', TRUE),
