  ('manus_ai_2026_05_03', 'Canadian scholarships and fellowships for developing country students', 'IDRC Research Awards 2025', 'International Development Research Centre (IDRC), Canada', 'Canada', 'https://idrc-crdi.ca/en/funding/idrc-research-awards-2025', 'stipend', 'One-year paid program of research with salaries up to CAD 54,756 in Ottawa. Covers research, development of complementary skills, and hands-on experience in research management.', NULL, ARRAY['phd','master']::text[], NULL, NULL, 'Citizens of developing countries (specific countries vary by award)', 'Undertake a master’s or doctoral-level research degree at a recognized Canadian university. Specific criteria vary by award. Focus on Climate-resilient food systems (based in Nairobi).', '2024-09-22'::date, 'fixed', NULL, NULL, 'International Development Research Centre (IDRC), Canada', 'Master''s or Doctoral-level research degree', 'Citizens of developing countries (specific countries vary by award)', 'One-year paid program of research with salaries up to CAD 54,756 in Ottawa. Covers research, development of complementary skills, and hands-on experience in research management.', 'Not explicitly stated.', 'Undertake a master’s or doctoral-level research degree at a recognized Canadian university. Specific criteria vary by award. Focus on Climate-resilient food systems (based in Nairobi).', 'September 22, 2024 (for 2025 awards).', 'https://idrc-crdi.ca/en/funding/idrc-research-awards-2025', TRUE),
  ('manus_ai_2026_05_03', 'Japanese government and university scholarships for developing country students (MEXT and others)', 'Japanese Government (MEXT) Scholarship', 'Japan (Ministry of Education, Culture, Sports, Science and Technology - MEXT) - Research Students: Under 35, eligible for master''s or doctoral program. - Teacher Training Students: Under 35, college/teacher training college graduate, 5+ years teaching experience. - Undergraduate Students: Under 25, completed 12 years of education. - Japanese Studies Students: 18-29, enrolled in Japanese language/culture program at a university outside Japan. - College of Technology Students: Under 25, completed 11+ years of education. - Specialized Training College Students: Under 25, completed 12 years of schooling. - Young Leaders Program (YLP) Students: Under 40, university/college graduates with practical work experience.', 'Japan', 'https://www.studyinjapan.go.jp/en/planning/scholarships/mext-scholarships/', 'tuition_only', 'Monthly stipend (¥117,000 - ¥242,000 depending on program), tuition exempted, round-trip airfare provided.', NULL, ARRAY['phd','master','bachelor']::text[], NULL, NULL, 'Developing countries (specific countries vary by embassy recommendation), international students', NULL, NULL, 'varies', NULL, NULL, 'Japan (Ministry of Education, Culture, Sports, Science and Technology - MEXT) - Research Students: Under 35, eligible for master''s or doctoral program. - Teacher Training Students: Under 35, college/teacher training college graduate, 5+ years teaching experience. - Undergraduate Students: Under 25, completed 12 years of education. - Japanese Studies Students: 18-29, enrolled in Japanese language/culture program at a university outside Japan. - College of Technology Students: Under 25, completed 11+ years of education. - Specialized Training College Students: Under 25, completed 12 years of schooling. - Young Leaders Program (YLP) Students: Under 40, university/college graduates with practical work experience.', 'Undergraduate, Master''s (Research Students, YLP), PhD (Research Students), Teacher Training, Japanese Studies, College of Technology, Specialized Training College', 'Developing countries (specific countries vary by embassy recommendation), international students', 'Monthly stipend (¥117,000 - ¥242,000 depending on program), tuition exempted, round-trip airfare provided.', 'Not specified, but multiple types available.', NULL, 'Varies by embassy/university recommendation. Typically announced annually.', 'https://www.studyinjapan.go.jp/en/planning/scholarships/mext-scholarships/', TRUE),
  ('manus_ai_2026_05_03', 'Japanese government and university scholarships for developing country students (MEXT and others)', 'Honjo International Scholarship Foundation Scholarship for Foreign Students', 'Honjo International Scholarship Foundation, Japan', 'Japan', 'https://www.hisf.or.jp/en/scholarship/foreigner/', 'stipend', 'Monthly stipend (¥180,000 - ¥230,000 depending on degree duration). Can be combined with MEXT Scholarship, Monbukagakusho Honors Scholarship, JSPS International Fellowship, and JST Fellowship.', NULL, ARRAY['phd','master']::text[], NULL, NULL, 'All nationalities', 'Foreign students studying or planning to study in a Japanese graduate school for a doctoral or master’s degree. Applications can be submitted from abroad if accepted to a Japanese graduate school. All nationalities and research fields are welcome. Applicants may directly apply to the foundation without pre-selection by the university.', NULL, 'fixed', NULL, NULL, 'Honjo International Scholarship Foundation, Japan', 'Master''s, PhD (graduate school level)', 'All nationalities', 'Monthly stipend (¥180,000 - ¥230,000 depending on degree duration). Can be combined with MEXT Scholarship, Monbukagakusho Honors Scholarship, JSPS International Fellowship, and JST Fellowship.', 'Approximately 10 students', 'Foreign students studying or planning to study in a Japanese graduate school for a doctoral or master’s degree. Applications can be submitted from abroad if accepted to a Japanese graduate school. All nationalities and research fields are welcome. Applicants may directly apply to the foundation without pre-selection by the university.', 'September 1 – October 31 (precise dates announced in application guideline)', 'https://www.hisf.or.jp/en/scholarship/foreigner/', TRUE),
  ('manus_ai_2026_05_03', 'Japanese government and university scholarships for developing country students (MEXT and others)', 'ADB-Japan Scholarship Program (JSP)', 'Asian Development Bank (ADB) with financing from the Government of Japan - National of an ADB borrowing member country and Japanese ODA scholarship-eligible country. - Not hold dual citizenship of any developed country. - Gained admission to an approved master’s course at a Designated Institution. - Hold a bachelor''s degree or its equivalent with superior academic record. - At least two (2) years of full-time professional working experience (acquired after a university degree). - Proficiency in oral and written English communication skills. - Not more than 35 years old at the time of application (unless waived). - Good health. - Agree to return and work in home country for at least two (2) years after completion of studies. - Not an Executive Director, Alternate Director, management, staff, or consultant of ADB, or their close relatives. - Not a staff of ADB–Japan Scholarship Program Designated Institutions. - Not living or working in a country other than home country. - Not already enrolled in graduate degree programs.', 'Japan', 'https://www.adb.org/work-with-us/careers/japan-scholarship-program/', 'tuition_only', 'Full tuition fees, monthly subsistence allowance (including housing), books and instructional materials, medical insurance, travel expenses. Special grant for thesis preparation may be available.', NULL, ARRAY['master']::text[], NULL, ARRAY['Afghanistan','Bangladesh','Cambodia','India','Indonesia','Kyrgyzstan','Myanmar','Nepal','Pakistan','Philippines','Sri Lanka','Tajikistan','Thailand','Timor-Leste','Uzbekistan','Vietnam']::text[], 'Citizens from ADB borrowing member countries and Japanese ODA scholarship-eligible countries (e.g., Afghanistan, Bangladesh, Cambodia, India, Indonesia, Kyrgyz Republic, Lao PDR, Myanmar, Nepal, Pakistan, Philippines, Sri Lanka, Tajikistan, Thailand, Timor-Leste, Uzbekistan, Vietnam, etc.)', NULL, NULL, 'varies', NULL, NULL, 'Asian Development Bank (ADB) with financing from the Government of Japan - National of an ADB borrowing member country and Japanese ODA scholarship-eligible country. - Not hold dual citizenship of any developed country. - Gained admission to an approved master’s course at a Designated Institution. - Hold a bachelor''s degree or its equivalent with superior academic record. - At least two (2) years of full-time professional working experience (acquired after a university degree). - Proficiency in oral and written English communication skills. - Not more than 35 years old at the time of application (unless waived). - Good health. - Agree to return and work in home country for at least two (2) years after completion of studies. - Not an Executive Director, Alternate Director, management, staff, or consultant of ADB, or their close relatives. - Not a staff of ADB–Japan Scholarship Program Designated Institutions. - Not living or working in a country other than home country. - Not already enrolled in graduate degree programs.', 'Graduate studies (Master''s)', 'Citizens from ADB borrowing member countries and Japanese ODA scholarship-eligible countries (e.g., Afghanistan, Bangladesh, Cambodia, India, Indonesia, Kyrgyz Republic, Lao PDR, Myanmar, Nepal, Pakistan, Philippines, Sri Lanka, Tajikistan, Thailand, Timor-Leste, Uzbekistan, Vietnam, etc.)', 'Full tuition fees, monthly subsistence allowance (including housing), books and instructional materials, medical insurance, travel expenses. Special grant for thesis preparation may be available.', 'About 130 graduate scholarships a year', NULL, 'Varies by partner institution. Applicants request information and application forms from partner institutions.', 'https://www.adb.org/work-with-us/careers/japan-scholarship-program/', TRUE),
