  ('manus_ai_2026_05_03', 'South Korean government scholarships for developing country students', 'Global Korea Scholarship (GKS)', 'South Korean Government (NIIED)', 'South Korea', 'https://www.studyinkorea.go.kr/in/plan/scholarship.do', 'full_ride', 'Airfare, Korean language training costs, full tuition, and study allowances (living expenses, medical insurance, settlement allowance).', NULL, ARRAY['phd','master','bachelor']::text[], NULL, NULL, 'Non-Korean citizens, with both parents holding non-Korean citizenship. Specific countries are designated by NIIED.', 'Must be under 40 years of age. Must have an average GPA of at least 80% from the most recent academic program. Applicants for graduate programs must have a Bachelor''s or Master''s degree. Overseas Koreans without Korean citizenship are also eligible.', NULL, 'fixed', NULL, NULL, 'South Korean Government (NIIED)', 'Associate Degree, Bachelor''s Degree, Master''s Degree, Doctoral Degree', 'Non-Korean citizens, with both parents holding non-Korean citizenship. Specific countries are designated by NIIED.', 'Airfare, Korean language training costs, full tuition, and study allowances (living expenses, medical insurance, settlement allowance).', 'Approximately 500 undergraduates (including associate degrees) + 1,900 graduate students (Total 2,400).', 'Must be under 40 years of age. Must have an average GPA of at least 80% from the most recent academic program. Applicants for graduate programs must have a Bachelor''s or Master''s degree. Overseas Koreans without Korean citizenship are also eligible.', 'Application period typically runs from February to March (Embassy Track and University Track).', 'https://www.studyinkorea.go.kr/in/plan/scholarship.do', TRUE),
